import dash
import dash_core_components as dcc
import dash_html_components as html
from dash.dependencies import Input, Output
import plotly.express as px
import pandas as pd
import numpy as np
from stravalib import Client
from polar import PolarFlow
from myfitnesspal import MyFitnessPal

# Initialize dash app
app = dash.Dash(__name__)

# Initialize fitness apps
strava_client = Client()
polar_flow = PolarFlow()
myfitnesspal = MyFitnessPal()

# Define layout
app.layout = html.Div([
    html.H1('Workout Tracking App'),
    html.Div([
        html.Button('Connect to Strava', id='strava-button', n_clicks=0),
        html.Button('Connect to Polar Flow', id='polar-button', n_clicks=0),
        html.Button('Connect to MyFitnessPal', id='myfitnesspal-button', n_clicks=0)
    ]),
    html.Div([
        dcc.Dropdown(
            id='view-dropdown',
            options=[
                {'label': 'By Sport', 'value': 'sport'},
                {'label': 'By Mileage', 'value': 'mileage'},
                {'label': 'By Heart Rate', 'value': 'heart_rate'}
            ],
            value='sport'
        )
    ]),
    html.Div([
        dcc.Graph(id='progress-graph')
    ]),
    html.Div([
        html.P('Total Time:'),
        html.P(id='total-time')
    ]),
    html.Div([
        html.P('Total Distance:'),
        html.P(id='total-distance')
    ]),
    html.Div([
        html.P('Total Calories Burned:'),
        html.P(id='total-calories')
    ])
])

# Define callbacks
@app.callback(
    Output('progress-graph', 'figure'),
    [Input('view-dropdown', 'value')]
)
def update_progress_graph(view):
    if view == 'sport':
        fig = px.bar(x=['Running', 'Cycling', 'Swimming'], y=[10, 20, 30])
    elif view == 'mileage':
        fig = px.line(x=np.arange(10), y=np.random.randint(0, 100, 10))
    elif view == 'heart_rate':
        fig = px.bar(x=['Zone 1', 'Zone 2', 'Zone 3'], y=[10, 20, 30])
    return fig

@app.callback(
    Output('total-time', 'children'),
    [Input('view-dropdown', 'value')]
)
def update_total_time(view):
    if view == 'sport':
        return '10 hours'
    elif view == 'mileage':
        return '20 hours'
    elif view == 'heart_rate':
        return '30 hours'

@app.callback(
    Output('total-distance', 'children'),
    [Input('view-dropdown', 'value')]
)
def update_total_distance(view):
    if view == 'sport':
        return '100 km'
    elif view == 'mileage':
        return '200 km'
    elif view == 'heart_rate':
        return '300 km'

@app.callback(
    Output('total-calories', 'children'),
    [Input('view-dropdown', 'value')]
)
def update_total_calories(view):
    if view == 'sport':
        return '1000 calories'
    elif view == 'mileage':
        return '2000 calories'
    elif view == 'heart_rate':
        return '3000 calories'

# Run app
if __name__ == '__main__':
    app.run_server(debug=True)

