from stravalib import Client
from polarflow import PolarFlow
from myfitnesspal import MyFitnessPal

class WorkoutTracker:
    def __init__(self, strava_client_id, polar_flow_username, myfitnesspal_username):
        self.strava_client = Client(client_id=strava_client_id)
        self.polar_flow = PolarFlow(polar_flow_username)
        self.myfitnesspal = MyFitnessPal(myfitnesspal_username)
        self.workouts = []
        self.nutrition = []

    def import_strava_workouts(self):
        activities = self.strava_client.get_activities()
        for activity in activities:
            self.workouts.append({
                'date': activity.start_date,
                'sport': activity.type,
                'distance': activity.distance.get_num(),
                'time': activity.elapsed_time.total_seconds(),
                'heart_rate': activity.average_heartrate
            })

    def import_polar_flow_workouts(self):
        exercises = self.polar_flow.get_exercises()
        for exercise in exercises:
            self.workouts.append({
                'date': exercise.date,
                'sport': exercise.type,
                'distance': exercise.distance,
                'time': exercise.duration,
                'heart_rate': exercise.heart_rate
            })

    def import_myfitnesspal_nutrition(self):
        diary = self.myfitnesspal.get_diary()
        for entry in diary:
            self.nutrition.append({
                'date': entry.date,
                'calories': entry.calories,
                'protein': entry.protein,
                'carbs': entry.carbs,
                'fat': entry.fat
            })

    def get_dashboard(self):
        dashboard = {}
        for workout in self.workouts:
            if workout['sport'] not in dashboard:
                dashboard[workout['sport']] = []
            dashboard[workout['sport']].append(workout)
        return dashboard

    def get_heart_rate_zones(self):
        heart_rate_zones = {}
        for workout in self.workouts:
            if workout['heart_rate'] not in heart_rate_zones:
                heart_rate_zones[workout['heart_rate']] = 0
            heart_rate_zones[workout['heart_rate']] += workout['time']
        return heart_rate_zones

    def plot_progress(self, by):
        if by == 'pace':
            plt.plot([workout['time'] / workout['distance'] for workout in self.workouts])
        elif by == 'mileage':
            plt.plot([workout['distance'] for workout in self.workouts])
        plt.show()

