import pandas as pd
import matplotlib.pyplot as plt
from stravalib import Client
from polarflow import PolarFlow
from myfitnesspal import MyFitnessPal

class WorkoutTracker:
    def __init__(self, strava_token, polar_flow_token, myfitnesspal_token):
        self.strava_client = Client(access_token=strava_token)
        self.polar_flow_client = PolarFlow(token=polar_flow_token)
        self.myfitnesspal_client = MyFitnessPal(token=myfitnesspal_token)
        self.workouts = []
        self.nutrition = []

