                'date': activity.start_date,
                'type': activity.type,
                'distance': activity.distance.get_num(),
                'moving_time': activity.moving_time.total_seconds(),
                'heart_rate': activity.heart_rate.get_num()
            }
            self.workouts.append(workout)

    def get_polar_flow_workouts(self):
        workouts = self.polar_flow_client.get_workouts()
        for workout in workouts:
            exercise = {
                'date': workout['date'],
                'type': workout['type'],
                'distance': workout['distance'],
                'moving_time': workout['duration'],
                'heart_rate': workout['heart_rate']
            }
            self.workouts.append(exercise)

    def get_myfitnesspal_nutrition(self):
        nutrition = self.myfitnesspal_client.get_nutrition()
        for entry in nutrition:
            self.nutrition.append({
                'date': entry['date'],
                'calories': entry['calories'],
                'carbs': entry['carbs'],
                'protein': entry['protein'],
                'fat': entry['fat']
            })

    def aggregate_heart_rate(self):
        heart_rate_data = {}
        for workout in self.workouts:
            if workout['heart_rate']:
                if workout['heart_rate'] not in heart_rate_data:
                    heart_rate_data[workout['heart_rate']] = 0
                heart_rate_data[workout['heart_rate']] += workout['moving_time']
        return heart_rate_data

    def plot_progress(self, metric):
        if metric == 'pace':
            x = [workout['date'] for workout in self.workouts]
            y = [workout['moving_time'] / workout['distance'] for workout in self.workouts]
        elif metric == 'mileage':
            x = [workout['date'] for workout in self.workouts]
            y = [workout['distance'] for workout in self.workouts]
        plt.plot(x, y)
        plt.xlabel('Date')
        plt.ylabel(metric.capitalize())
        plt.title('Progress Over Time')
        plt.show()

    def filter_by_sport(self, sport):
        return [workout for workout in self.workouts if workout['type'] == sport]

    def filter_by_mileage(self, mileage):
        return [workout for workout in self.workouts if workout['distance'] >= mileage]

