import pandas as pd
import matplotlib.pyplot as plt
from stravalib import Client
from polarflow import PolarFlow
from myfitnesspal import MyFitnessPal

class WorkoutTracker:
    def __init__(self, strava_client_id, strava_client_secret, polar_flow_username, polar_flow_password, myfitnesspal_username, myfitnesspal_password):
        self.strava_client = Client(client_id=strava_client_id, client_secret=strava_client_secret)
        self.polar_flow_client = PolarFlow(username=polar_flow_username, password=polar_flow_password)
        self.myfitnesspal_client = MyFitnessPal(username=myfitnesspal_username, password=myfitnesspal_password)
        self.workouts = []
        self.nutrition = []

    def get_strava_workouts(self):
        activities = self.strava_client.get_activities(limit=100)
        for activity in activities:
            workout = {
                'date': activity.start_date,
                'sport': activity.type,
                'distance': activity.distance.get_num(),
                'duration': activity.elapsed_time.total_seconds(),
                'heart_rate': activity.average_heartrate
            }
            self.workouts.append(workout)

    def get_polar_flow_workouts(self):
        exercises = self.polar_flow_client.get_exercises()
        for exercise in exercises:
            workout = {
                'date': exercise.date,
                'sport': exercise.sport,
                'distance': exercise.distance,
                'duration': exercise.duration,
                'heart_rate': exercise.average_heart_rate
            }
            self.workouts.append(workout)

    def get_myfitnesspal_nutrition(self):
        diary = self.myfitnesspal_client.get_diary()
        for entry in diary:
            nutrition = {
                'date': entry.date,
                'calories': entry.calories,
                'protein': entry.protein,
                'carbohydrates': entry.carbohydrates,
                'fat': entry.fat
            }
            self.nutrition.append(nutrition)

    def aggregate_heart_rate(self):
        heart_rate_data = {}
        for workout in self.workouts:
            if workout['heart_rate'] is not None:
                if workout['heart_rate'] < 120:
                    zone = 'low'
                elif workout['heart_rate'] < 140:
                    zone = 'moderate'
                else:
                    zone = 'high'
                if zone not in heart_rate_data:
                    heart_rate_data[zone] = 0
                heart_rate_data[zone] += workout['duration']
        return heart_rate_data

    def plot_progress(self, metric):
        if metric == 'pace':
            x = [workout['date'] for workout in self.workouts]
            y = [workout['distance'] / workout['duration'] for workout in self.workouts]
        elif metric == 'mileage':
            x = [workout['date'] for workout in self.workouts]
            y = [workout['distance'] for workout in self.workouts]
        plt.plot(x, y)
        plt.xlabel('Date')
        plt.ylabel(metric.capitalize())
        plt.show()

    def dashboard(self):
        self.get_strava_workouts()
        self.get_polar_flow_workouts()
        self.get_myfitnesspal_nutrition()
        heart_rate_data = self.aggregate_heart_rate()
        print('Heart Rate Data:')
        for zone, duration in heart_rate_data.items():
            print(f'{zone}: {duration} seconds')
        print('Workouts:')
        for workout in self.workouts:
            print(f"Date: {workout['date']}, Sport: {workout['sport']}, Distance: {workout['distance']}, Duration: {workout['duration']}")
        print('Nutrition:')
        for nutrition in self.nutrition:
            print(f"Date: {nutrition['date']}, Calories: {nutrition['calories']}, Protein: {nutrition['protein']}, Carbohydrates: {nutrition['carbohydrates']}, Fat: {nutrition['fat']}")
        metric = input('Enter metric to plot (pace or mileage): ')
        self.plot_progress(metric)

