import pandas as pd
import matplotlib.pyplot as plt
from stravalib import Client
from polarflow import PolarFlow
from myfitnesspal import MyFitnessPal

class WorkoutApp:
    def __init__(self):
        self.strava_client = Client()
        self.polar_flow = PolarFlow()
        self.myfitnesspal = MyFitnessPal()

    def import_strava_data(self):
        activities = self.strava_client.get_activities()
        data = []
        for activity in activities:
            data.append({
                'date': activity.start_date,
                'distance': activity.distance.get_num(),
                'time': activity.elapsed_time.total_seconds(),
                'heart_rate': activity.average_heartrate,
                'sport': activity.type
            })
        return pd.DataFrame(data)

    def import_polar_flow_data(self):
        exercises = self.polar_flow.get_exercises()
        data = []
        for exercise in exercises:
            data.append({
                'date': exercise.date,
                'distance': exercise.distance,
                'time': exercise.duration,
                'heart_rate': exercise.average_heart_rate,
                'sport': exercise.sport
            })
        return pd.DataFrame(data)

    def import_myfitnesspal_data(self):
        diary = self.myfitnesspal.get_diary()
        data = []
        for entry in diary:
            data.append({
                'date': entry.date,
                'calories': entry.calories,
                'macronutrients': entry.macronutrients
            })
        return pd.DataFrame(data)

    def combine_data(self):
        strava_data = self.import_strava_data()
        polar_flow_data = self.import_polar_flow_data()
        myfitnesspal_data = self.import_myfitnesspal_data()
        combined_data = pd.concat([strava_data, polar_flow_data])
        combined_data = pd.merge(combined_data, myfitnesspal_data, on='date', how='left')
        return combined_data

    def filter_by_sport(self, data, sport):
        return data[data['sport'] == sport]

    def filter_by_mileage(self, data, mileage):
        return data[data['distance'] > mileage]

    def calculate_heart_rate_zones(self, data):
        zones = {
            'low': 0,
            'moderate': 0,
            'high': 0
        }
        for index, row in data.iterrows():
            if row['heart_rate'] < 120:
                zones['low'] += row['time']
            elif row['heart_rate'] < 140:
                zones['moderate'] += row['time']
            else:
                zones['high'] += row['time']
        return zones

    def plot_progress(self, data, metric):
        if metric == 'pace':
            data['pace'] = data['time'] / data['distance']
            plt.plot(data['date'], data['pace'])
        elif metric == 'mileage':
            plt.plot(data['date'], data['distance'])
        plt.xlabel('Date')
        plt.ylabel(metric.capitalize())
        plt.show()

def main():
    app = WorkoutApp()
    data = app.combine_data()
    sport = input("Enter sport: ")
    filtered_data = app.filter_by_sport(data, sport)
    mileage = int(input("Enter minimum mileage: "))
    filtered_data = app.filter_by_mileage(filtered_data, mileage)
    zones = app.calculate_heart_rate_zones(filtered_data)
    print("Heart rate zones:")
    print(zones)
    metric = input("Enter metric to plot (pace/mileage): ")
    app.plot_progress(filtered_data, metric)

if __name__ == "__main__":
    main()

import pandas as pd
import matplotlib.pyplot as plt
from stravalib import Client
from polarflow import PolarFlow
from myfitnesspal import MyFitnessPal

class WorkoutApp:
    def __init__(self):
        self.strava_client = Client()
        self.polar_flow = PolarFlow()
        self.myfitnesspal = MyFitnessPal()

    def import_data(self):
        strava_data = self.strava_client.get_activities()
        polar_flow_data = self.polar_flow.get_workouts()
        myfitnesspal_data = self.myfitnesspal.get_diary()
        return strava_data, polar_flow_data, myfitnesspal_data

    def combine_data(self, strava_data, polar_flow_data, myfitnesspal_data):
        combined_data = []
        for activity in strava_data:
            combined_data.append({
                'date': activity.start_date,
                'sport': activity.type,
                'distance': activity.distance.get_num(),
                'time': activity.elapsed_time.total_seconds(),
                'heart_rate': activity.average_heartrate
            })
        for workout in polar_flow_data:
            combined_data.append({
                'date': workout.date,
                'sport': workout.type,
                'distance': workout.distance,
                'time': workout.duration,
                'heart_rate': workout.average_heart_rate
            })
        for entry in myfitnesspal_data:
            combined_data.append({
                'date': entry.date,
                'sport': 'nutrition',
                'distance': 0,
                'time': 0,
                'heart_rate': 0,
                'calories': entry.calories
            })
        return pd.DataFrame(combined_data)

    def filter_data(self, data, sport=None, mileage=None):
        if sport:
            data = data[data['sport'] == sport]
        if mileage:
            data = data[data['distance'] > mileage]
        return data

    def calculate_heart_rate_zones(self, data):
        zones = {
            'low': 0,
            'moderate': 0,
            'high': 0,
            'very_high': 0
        }
        for index, row in data.iterrows():
            if row['heart_rate'] < 120:
                zones['low'] += row['time']
            elif row['heart_rate'] < 140:
                zones['moderate'] += row['time']
            elif row['heart_rate'] < 160:
                zones['high'] += row['time']
            else:
                zones['very_high'] += row['time']
        return zones

    def plot_progress(self, data, metric):
        if metric == 'pace':
            plt.plot(data['date'], data['distance'] / data['time'])
        elif metric == 'mileage':
            plt.plot(data['date'], data['distance'])
        plt.xlabel('Date')
        plt.ylabel(metric.capitalize())
        plt.show()

    def run(self):
        strava_data, polar_flow_data, myfitnesspal_data = self.import_data()
        combined_data = self.combine_data(strava_data, polar_flow_data, myfitnesspal_data)
        sport = input("Enter sport (or leave blank for all): ")
        mileage = int(input("Enter minimum mileage (or 0 for all): "))
        filtered_data = self.filter_data(combined_data, sport, mileage)
        heart_rate_zones = self.calculate_heart_rate_zones(filtered_data)
        print("Heart Rate Zones:")
        for zone, time in heart_rate_zones.items():
            print(f"{zone.capitalize()}: {time} seconds")
        metric = input("Enter metric to plot (pace or mileage): ")
        self.plot_progress(filtered_data, metric)

app = WorkoutApp()
app.run()

import pandas as pd
import matplotlib.pyplot as plt
from stravalib import Client
from polarflow import PolarFlow
from myfitnesspal import MyFitnessPal

class WorkoutGo:
    def __init__(self, strava_token, polar_flow_token, myfitnesspal_token):
        self.strava_token = strava_token
        self.polar_flow_token = polar_flow_token
        self.myfitnesspal_token = myfitnesspal_token
        self.strava_client = Client(access_token=self.strava_token)
        self.polar_flow_client = PolarFlow(self.polar_flow_token)
        self.myfitnesspal_client = MyFitnessPal(self.myfitnesspal_token)

    def get_strava_data(self):
        activities = self.strava_client.get_activities()
        data = []
        for activity in activities:
            data.append({
                'date': activity.start_date,
                'sport': activity.type,
                'distance': activity.distance.get_num(),
                'time': activity.elapsed_time.total_seconds() / 3600,
                'heart_rate': activity.heart_rate
            })
        return pd.DataFrame(data)

    def get_polar_flow_data(self):
        exercises = self.polar_flow_client.get_exercises()
        data = []
        for exercise in exercises:
            data.append({
                'date': exercise.start_time,
                'sport': exercise.sport,
                'distance': exercise.distance,
                'time': exercise.duration / 3600,
                'heart_rate': exercise.heart_rate
            })
        return pd.DataFrame(data)

    def get_myfitnesspal_data(self):
        diary = self.myfitnesspal_client.get_diary()
        data = []
        for entry in diary:
            data.append({
                'date': entry.date,
                'calories': entry.calories,
                'protein': entry.protein,
                'carbs': entry.carbs,
                'fat': entry.fat
            })
        return pd.DataFrame(data)

    def combine_data(self):
        strava_data = self.get_strava_data()
        polar_flow_data = self.get_polar_flow_data()
        myfitnesspal_data = self.get_myfitnesspal_data()
        combined_data = pd.concat([strava_data, polar_flow_data])
        combined_data = pd.merge(combined_data, myfitnesspal_data, on='date', how='left')
        return combined_data

    def plot_progress(self, sport=None, stat=None):
        data = self.combine_data()
        if sport:
            data = data[data['sport'] == sport]
        if stat:
            plt.plot(data['date'], data[stat])
        else:
            plt.plot(data['date'], data['distance'])
        plt.xlabel('Date')
        plt.ylabel('Distance')
        plt.title('Progress Over Time')
        plt.show()

    def plot_heart_rate_zones(self):
        data = self.combine_data()
        zones = {
            'low': (0, 120),
            'medium': (121, 140),
            'high': (141, 160),
            'very_high': (161, 180)
        }
        zone_data = []
        for index, row in data.iterrows():
            for zone, (low, high) in zones.items():
                if low <= row['heart_rate'] <= high:
                    zone_data.append({
                        'zone': zone,
                        'time': row['time']
                    })
        zone_df = pd.DataFrame(zone_data)
        zone_df = zone_df.groupby('zone')['time'].sum().reset_index()
        plt.bar(zone_df['zone'], zone_df['time'])
        plt.xlabel('Zone')
        plt.ylabel('Time')
        plt.title('Time Spent in Heart Rate Zones')
        plt.show()

    def plot_pace(self, sport=None):
        data = self.combine_data()
        if sport:
            data = data[data['sport'] == sport]
        plt.plot(data['date'], data['distance'] / data['time'])
        plt.xlabel('Date')
        plt.ylabel('Pace')
        plt.title('Pace Over Time')
        plt.show()

    def plot_mileage(self, sport=None):
        data = self.combine_data()
        if sport:
            data = data[data['sport'] == sport]
        plt.plot(data['date'], data['distance'])
        plt.xlabel('Date')
        plt.ylabel('Mileage')
        plt.title('Mileage Over Time')
        plt.show()

def main():
    strava_token = 'your_strava_token'
    polar_flow_token = 'your_polar_flow_token'
    myfitnesspal_token = 'your_myfitnesspal_token'
    workout_go = WorkoutGo(strava_token, polar_flow_token, myfitnesspal_token)
    while True:
        print('1. Plot Progress')
        print('2. Plot Heart Rate Zones')
        print('3. Plot Pace')
        print('4. Plot Mileage')
        choice = input('Enter your choice: ')
        if choice == '1':
            sport = input('Enter sport (optional): ')
            stat = input('Enter stat (optional): ')
            workout_go.plot_progress(sport or None, stat or None)
        elif choice == '2':
            workout_go.plot_heart_rate_zones()
