import pandas as pd
import matplotlib.pyplot as plt
from stravalib import Client
from polar import Polar
from myfitnesspal import MyFitnessPal

class WorkoutTracker:
    def __init__(self, strava_token, polar_token, myfitnesspal_token):
        self.strava_client = Client(access_token=strava_token)
        self.polar_client = Polar(polar_token)
        self.myfitnesspal_client = MyFitnessPal(myfitnesspal_token)
        self.workouts = []
        self.nutrition = []

    def import_strava_workouts(self):
        activities = self.strava_client.get_activities(limit=100)
        for activity in activities:
            self.workouts.append({
                'date': activity.start_date,
                'type': activity.type,
                'distance': activity.distance.get_num(),
                'duration': activity.elapsed_time.total_seconds(),
                'heart_rate': activity.average_heartrate
            })

    def import_polar_workouts(self):
        workouts = self.polar_client.get_workouts()
        for workout in workouts:
            self.workouts.append({
                'date': workout['date'],
                'type': workout['type'],
                'distance': workout['distance'],
                'duration': workout['duration'],
                'heart_rate': workout['heart_rate']
            })

    def import_myfitnesspal_nutrition(self):
        nutrition = self.myfitnesspal_client.get_nutrition()
        for entry in nutrition:
            self.nutrition.append({
                'date': entry['date'],
                'calories': entry['calories'],
                'protein': entry['protein'],
                'carbs': entry['carbs'],
                'fat': entry['fat']
            })

    def aggregate_heart_rate(self):
        heart_rate_data = {}
        for workout in self.workouts:
            if workout['heart_rate']:
                if workout['heart_rate'] < 120:
                    zone = 'low'
                elif workout['heart_rate'] < 140:
                    zone = 'medium'
                else:
                    zone = 'high'
                if zone not in heart_rate_data:
                    heart_rate_data[zone] = 0
                heart_rate_data[zone] += workout['duration']
        return heart_rate_data

    def plot_progress(self, by):
        if by == 'date':
            x = [workout['date'] for workout in self.workouts]
            y = [workout['distance'] for workout in self.workouts]
        elif by == 'mileage':
            x = [sum(workout['distance'] for workout in self.workouts[:i+1]) for i in range(len(self.workouts))]
            y = [workout['distance'] for workout in self.workouts]
        plt.plot(x, y)
        plt.xlabel(by)
        plt.ylabel('Distance')
        plt.show()

    def dashboard(self):
        print('Workouts:')
        for workout in self.workouts:
            print(f"Date: {workout['date']}, Type: {workout['type']}, Distance: {workout['distance']}, Duration: {workout['duration']}, Heart Rate: {workout['heart_rate']}")
        print('Nutrition:')
        for entry in self.nutrition:
            print(f"Date: {entry['date']}, Calories: {entry['calories']}, Protein: {entry['protein']}, Carbs: {entry['carbs']}, Fat: {entry['fat']}")
        heart_rate_data = self.aggregate_heart_rate()
        print('Heart Rate Zones:')
        for zone, duration in heart_rate_data.items():
            print(f"{zone}: {duration} seconds")
        by = input("Plot progress by (date/mileage): ")
        self.plot_progress(by)

