    data = []
    for activity in activities:
        data.append({
            'date': activity.start_date,
            'distance': activity.distance.get_num(),
            'calories': activity.calories,
            'heart_rate': activity.heart_rate,
            'sport': activity.type
        })
    return pd.DataFrame(data)

# Define a function to fetch data from Polar Flow
def fetch_polar_flow_data():
    workouts = polar_flow_client.get_workouts()
    data = []
    for workout in workouts:
        data.append({
            'date': workout.date,
            'distance': workout.distance,
            'calories': workout.calories,
            'heart_rate': workout.heart_rate,
            'sport': workout.sport
        })
    return pd.DataFrame(data)

# Define a function to fetch data from MyFitnessPal
