    myfitnesspal_data = myfitnesspal_client.get_diary()
    return strava_data, polar_flow_data, myfitnesspal_data

# Define a function to aggregate heart rate data
def aggregate_heart_rate(data):
    heart_rate_data = []
    for activity in data:
        heart_rate_data.extend(activity['heart_rate'])
    heart_rate_df = pd.DataFrame(heart_rate_data)
    heart_rate_df['intensity_zone'] = pd.cut(heart_rate_df['heart_rate'], bins=[0, 100, 120, 140, 160, 180], labels=['Low', 'Moderate', 'High', 'Very High', 'Extremely High'])
    heart_rate_df = heart_rate_df.groupby('intensity_zone')['heart_rate'].sum().reset_index()
    return heart_rate_df

