    if metric == 'distance':
        x_axis = 'distance'
        y_axis = 'date'
    elif metric == 'mileage':
        x_axis = 'mileage'
        y_axis = 'date'
    progress_df = pd.DataFrame(data)
    progress_df['date'] = pd.to_datetime(progress_df['date'])
    progress_df = progress_df.sort_values(by='date')
    fig = px.line(progress_df, x=x_axis, y=y_axis)
    return fig

