                'date': activity.start_date,
                'type': activity.type,
                'distance': activity.distance.num,
                'duration': activity.elapsed_time.total_seconds(),
                'heartrate': activity.average_heartrate
            })
        return pd.DataFrame(data)

    def get_polar_data(self):
        workouts = self.polar_api.get_workouts()
        data = []
        for workout in workouts:
            data.append({
                'date': workout['date'],
                'type': workout['type'],
                'distance': workout['distance'],
                'duration': workout['duration'],
                'heartrate': workout['heartrate']
            })
        return pd.DataFrame(data)

    def get_myfitnesspal_data(self):
        diary = self.myfitnesspal.get_diary()
        data = []
        for entry in diary:
            data.append({
                'date': entry['date'],
                'calories': entry['calories'],
                'macronutrients': entry['macronutrients']
            })
        return pd.DataFrame(data)

    def aggregate_data(self):
