import pandas as pd
import matplotlib.pyplot as plt
from strava import Client
from polar import FlowClient
from myfitnesspal import MyFitnessPalClient

class FitnessDashboard:
    def __init__(self, strava_client_id, strava_client_secret, polar_client_id, polar_client_secret, myfitnesspal_username, myfitnesspal_password):
        self.strava_client = Client(client_id=strava_client_id, client_secret=strava_client_secret)
        self.polar_client = FlowClient(client_id=polar_client_id, client_secret=polar_client_secret)
        self.myfitnesspal_client = MyFitnessPalClient(username=myfitnesspal_username, password=myfitnesspal_password)

    def get_strava_workouts(self):
        activities = self.strava_client.get_activities()
        workouts = []
        for activity in activities:
            workout = {
                'date': activity.start_date,
                'distance': activity.distance.get_num(),
                'duration': activity.elapsed_time.total_seconds() / 60,
                'heart_rate': activity.average_heartrate
            }
            workouts.append(workout)
        return pd.DataFrame(workouts)

    def get_polar_workouts(self):
        exercises = self.polar_client.get_exercises()
        workouts = []
        for exercise in exercises:
            workout = {
                'date': exercise.date,
                'distance': exercise.distance,
                'duration': exercise.duration,
                'heart_rate': exercise.average_heart_rate
            }
            workouts.append(workout)
        return pd.DataFrame(workouts)

    def get_myfitnesspal_diary(self):
        diary = self.myfitnesspal_client.get_diary()
        diary_entries = []
        for entry in diary:
            diary_entry = {
                'date': entry.date,
                'calories': entry.calories
            }
            diary_entries.append(diary_entry)
        return pd.DataFrame(diary_entries)

    def aggregate_workouts(self, workouts):
        aggregated_workouts = []
        for index, row in workouts.iterrows():
            aggregated_workout = {
                'date': row['date'],
                'total_distance': row['distance'],
                'total_duration': row['duration'],
                'total_heart_rate': row['heart_rate']
            }
            aggregated_workouts.append(aggregated_workout)
        return pd.DataFrame(aggregated_workouts)

    def plot_progress(self, workouts, metric):
        if metric == 'pace':
            plt.plot(workouts['date'], workouts['distance'] / workouts['duration'])
        elif metric == 'heart_rate':
            plt.plot(workouts['date'], workouts['heart_rate'])
        plt.xlabel('Date')
        plt.ylabel(metric.capitalize())
        plt.title('Progress Over Time')
        plt.show()

    def plot_heart_rate_zones(self, workouts):
        heart_rate_zones = []
        for index, row in workouts.iterrows():
            if row['heart_rate'] < 100:
                heart_rate_zones.append({'zone': 'Low', 'duration': row['duration']})
            elif row['heart_rate'] < 130:
                heart_rate_zones.append({'zone': 'Moderate', 'duration': row['duration']})
            elif row['heart_rate'] < 160:
                heart_rate_zones.append({'zone': 'High', 'duration': row['duration']})
            else:
                heart_rate_zones.append({'zone': 'Very High', 'duration': row['duration']})
        heart_rate_zones = pd.DataFrame(heart_rate_zones)
        heart_rate_zones = heart_rate_zones.groupby('zone')['duration'].sum().reset_index()
        plt.bar(heart_rate_zones['zone'], heart_rate_zones['duration'])
        plt.xlabel('Heart Rate Zone')
        plt.ylabel('Duration (minutes)')
        plt.title('Time Spent in Each Heart Rate Zone')
        plt.show()

def main():
    strava_client_id = 'your_strava_client_id'
    strava_client_secret = 'your_strava_client_secret'
    polar_client_id = 'your_polar_client_id'
    polar_client_secret = 'your_polar_client_secret'
    myfitnesspal_username = 'your_myfitnesspal_username'
    myfitnesspal_password = 'your_myfitnesspal_password'

    dashboard = FitnessDashboard(strava_client_id, strava_client_secret, polar_client_id, polar_client_secret, myfitnesspal_username, myfitnesspal_password)

    strava_workouts = dashboard.get_strava_workouts()
    polar_workouts = dashboard.get_polar_workouts()
    myfitnesspal_diary = dashboard.get_myfitnesspal_diary()

    workouts = pd.concat([strava_workouts, polar_workouts])
    aggregated_workouts = dashboard.aggregate_workouts(workouts)

    print("Select a metric to view progress:")
    print("1. Pace")
    print("2. Heart Rate")
    metric_choice = input("Enter your choice (1/2): ")
    if metric_choice == '1':
        dashboard.plot_progress(aggregated_workouts, 'pace')
    elif metric_choice == '2':
        dashboard.plot_progress(aggregated_workouts, 'heart_rate')

    dashboard.plot_heart_rate_zones(aggregated_workouts)

if __name__ == '__main__':
    main()

