    elif app == 'myfitnesspal':
        mfp = MyFitnessPal()
        diary = mfp.get_diary()
        df = pd.DataFrame([{'date': d.date, 'calories': d.calories, 'macronutrients': d.macronutrients} for d in diary])

    if metric == 'distance':
