            {'label': 'MyFitnessPal', 'value': 'myfitnesspal'}
        ],
        value='strava'
    ),
    html.P('Select metric:'),
    dcc.Dropdown(
        id='metric',
        options=[
            {'label': 'Distance', 'value': 'distance'},
