            {'label': 'Calories', 'value': 'calories'}
        ],
        value='distance'
    ),
    html.P('Select time period:'),
    dcc.Dropdown(
        id='time-period',
        options=[
            {'label': 'Day', 'value': 'day'},
            {'label': 'Week', 'value': 'week'},
            {'label': 'Month', 'value': 'month'}
        ],
        value='day'
    ),
    dcc.Graph(id='graph'),
    html.P('Intensity zones:'),
    dcc.Graph(id='intensity-zones')
])

@app.callback(
    Output('graph', 'figure'),
    [Input('data-source', 'value'),
     Input('metric', 'value'),
     Input('time-period', 'value')]
)
def update_graph(data_source, metric, time_period):
    if data_source == 'strava':
        client = Client()
        activities = client.get_activities(limit=100)
        data = []
        for activity in activities:
            data.append({
                'date': activity.start_date,
                'distance': activity.distance.get_num(),
                'heart_rate': activity.average_heartrate,
                'calories': activity.calories
            })
    elif data_source == 'polar':
        polar = PolarFlow()
        exercises = polar.get_exercises()
        data = []
        for exercise in exercises:
            data.append({
                'date': exercise['date'],
                'distance': exercise['distance'],
                'heart_rate': exercise['heart_rate'],
                'calories': exercise['calories']
            })
    elif data_source == 'myfitnesspal':
        mfp = MyFitnessPal()
        diary = mfp.get_diary()
        data = []
        for entry in diary:
            data.append({
                'date': entry['date'],
                'distance': 0,
                'heart_rate': 0,
                'calories': entry['calories']
            })
    df = pd.DataFrame(data)
    if time_period == 'day':
        df = df[df['date'].dt.date == pd.to_datetime('today').date()]
    elif time_period == 'week':
        df = df[df['date'].dt.date >= pd.to_datetime('today').date() - pd.DateOffset(days=7)]
    elif time_period == 'month':
        df = df[df['date'].dt.date >= pd.to_datetime('today').date() - pd.DateOffset(days=30)]
    if metric == 'distance':
        fig = px.line(df, x='date', y='distance')
    elif metric == 'heart_rate':
        fig = px.line(df, x='date', y='heart_rate')
    elif metric == 'calories':
        fig = px.line(df, x='date', y='calories')
    return fig

@app.callback(
    Output('intensity-zones', 'figure'),
    [Input('data-source', 'value')]
)
def update_intensity_zones(data_source):
    if data_source == 'strava':
        client = Client()
        activities = client.get_activities(limit=100)
        data = []
        for activity in activities:
            data.append({
                'heart_rate': activity.average_heartrate
            })
    elif data_source == 'polar':
        polar = PolarFlow()
        exercises = polar.get_exercises()
        data = []
        for exercise in exercises:
            data.append({
                'heart_rate': exercise['heart_rate']
            })
    df = pd.DataFrame(data)
    df['zone'] = pd.cut(df['heart_rate'], bins=[0, 100, 120, 140, 160, 180], labels=['Low', 'Moderate', 'High', 'Very High', 'Extremely High'])
    fig = px.bar(df, x='zone', y='heart_rate')
    return fig

if __name__ == '__main__':
    app.run_server(debug=True)

