            return self.strava_client.get_activities()
        elif app_name == 'Polar Flow':
            return self.polar_flow.get_workouts()
        elif app_name == 'MyFitnessPal':
            return self.myfitnesspal.get_diary()

    def aggregate_data(self, data):
        aggregated_data = {}
        for activity in data:
            if activity['type'] not in aggregated_data:
                aggregated_data[activity['type']] = {'distance': 0, 'time': 0, 'heart_rate': []}
            aggregated_data[activity['type']]['distance'] += activity['distance']
            aggregated_data[activity['type']]['time'] += activity['time']
            aggregated_data[activity['type']]['heart_rate'].extend(activity['heart_rate'])
        return aggregated_data

    def calculate_heart_rate_zones(self, heart_rate_data):
        zones = {'low': 0, 'medium': 0, 'high': 0}
        for heart_rate in heart_rate_data:
            if heart_rate < 120:
                zones['low'] += 1
            elif heart_rate < 140:
                zones['medium'] += 1
            else:
                zones['high'] += 1
        return zones

    def plot_progress(self, data, metric):
        if metric == 'distance':
            plt.plot([activity['distance'] for activity in data])
        elif metric == 'time':
            plt.plot([activity['time'] for activity in data])
        plt.show()

    def run(self):
        app_name = input("Enter the app name (Strava, Polar Flow, MyFitnessPal): ")
        data = self.import_data(app_name)
        aggregated_data = self.aggregate_data(data)
        for activity_type, activity_data in aggregated_data.items():
            heart_rate_zones = self.calculate_heart_rate_zones(activity_data['heart_rate'])
            print(f"Activity Type: {activity_type}")
            print(f"Distance: {activity_data['distance']}")
            print(f"Time: {activity_data['time']}")
            print(f"Heart Rate Zones: {heart_rate_zones}")
        metric = input("Enter the metric to plot (distance, time): ")
        self.plot_progress(data, metric)

if __name__ == "__main__":
    app = PhysicalExertionTagApp()
    app.run()

