import pandas as pd
import matplotlib.pyplot as plt
from stravalib import Client
from polarstream import PolarStream
from myfitnesspal import MyFitnessPal

class ExerciseApp:
    def __init__(self, strava_client_id, strava_client_secret, polar_stream_client_id, polar_stream_client_secret, myfitnesspal_username, myfitnesspal_password):
        self.strava_client = Client(client_id=strava_client_id, client_secret=strava_client_secret)
        self.polar_stream_client = PolarStream(client_id=polar_stream_client_id, client_secret=polar_stream_client_secret)
        self.myfitnesspal_client = MyFitnessPal(username=myfitnesspal_username, password=myfitnesspal_password)

    def get_strava_data(self):
        activities = self.strava_client.get_activities()
        data = []
        for activity in activities:
            data.append({
                'date': activity.start_date,
                'distance': activity.distance.get_num(),
                'moving_time': activity.moving_time.total_seconds(),
                'average_heartrate': activity.average_heartrate
            })
        return pd.DataFrame(data)

    def get_polar_stream_data(self):
        exercises = self.polar_stream_client.get_exercises()
        data = []
        for exercise in exercises:
            data.append({
                'date': exercise.start_time,
                'distance': exercise.distance,
                'duration': exercise.duration,
                'average_heart_rate': exercise.average_heart_rate
            })
        return pd.DataFrame(data)

    def get_myfitnesspal_data(self):
        diary = self.myfitnesspal_client.get_diary()
        data = []
        for entry in diary:
            data.append({
                'date': entry.date,
                'calories': entry.calories
            })
        return pd.DataFrame(data)

    def combine_data(self):
        strava_data = self.get_strava_data()
        polar_stream_data = self.get_polar_stream_data()
        myfitnesspal_data = self.get_myfitnesspal_data()
        combined_data = pd.concat([strava_data, polar_stream_data, myfitnesspal_data])
        return combined_data

    def plot_data(self, data, by='step'):
        if by == 'step':
            data['step_count'] = data['distance'] * 1000 / 1.5  # assume 1.5 meters per step
            plt.plot(data['date'], data['step_count'])
            plt.xlabel('Date')
            plt.ylabel('Step Count')
            plt.title('Step Count Over Time')
        elif by == 'mileage':
            plt.plot(data['date'], data['distance'])
            plt.xlabel('Date')
            plt.ylabel('Distance (m)')
            plt.title('Distance Over Time')
        plt.show()

    def calculate_center_pace(self, data):
        data['pace'] = data['moving_time'] / data['distance']
        pace_data = data.groupby('date')['pace'].mean().reset_index()
        return pace_data

    def plot_center_pace(self, pace_data):
        plt.plot(pace_data['date'], pace_data['pace'])
        plt.xlabel('Date')
        plt.ylabel('Center Pace (s/m)')
        plt.title('Center Pace Over Time')
        plt.show()

def main():
    app = ExerciseApp('strava_client_id', 'strava_client_secret', 'polar_stream_client_id', 'polar_stream_client_secret', 'myfitnesspal_username', 'myfitnesspal_password')
    combined_data = app.combine_data()
    by = 'step'  # or 'mileage'
    app.plot_data(combined_data, by)
    pace_data = app.calculate_center_pace(combined_data)
    app.plot_center_pace(pace_data)

if __name__ == '__main__':
    main()

