import streamlit as st
import pandas as pd
import matplotlib.pyplot as plt
from requests import get

def fetch_strava_data(athlete_id, access_token):
    url = f"https://www.strava.com/api/v3/athletes/{athlete_id}/activities"
    headers = {"Authorization": f"Bearer {access_token}"}
    response = get(url, headers=headers)
    return response.json()

def fetch_polar_data(user_id, access_token):
    url = f"https://www.polaraccesslink.com/v3/users/{user_id}/exercises"
    headers = {"Authorization": f"Bearer {access_token}"}
    response = get(url, headers=headers)
    return response.json()

def fetch_myfitnesspal_data(user_id, password):
    url = f"https://api.myfitnesspal.com/v2/diary/{user_id}"
    auth = (user_id, password)
    response = get(url, auth=auth)
    return response.json()

def aggregate_data(strava_data, polar_data, myfitnesspal_data):
    aggregated_data = []
    for activity in strava_data:
        aggregated_data.append({
            "date": activity["start_date"],
            "distance": activity["distance"],
            "duration": activity["moving_time"],
            "heart_rate": activity["average_heartrate"]
        })
    for exercise in polar_data:
        aggregated_data.append({
            "date": exercise["date"],
            "distance": exercise["distance"],
            "duration": exercise["duration"],
            "heart_rate": exercise["heart_rate"]
        })
    for entry in myfitnesspal_data:
        aggregated_data.append({
            "date": entry["date"],
            "calories": entry["calories"],
            "protein": entry["protein"],
            "fat": entry["fat"],
            "carbohydrates": entry["carbohydrates"]
        })
    return aggregated_data

def calculate_heart_rate_zones(heart_rate_data):
    zones = {}
    for entry in heart_rate_data:
        if entry["heart_rate"] < 120:
            zone = "Low"
        elif entry["heart_rate"] < 140:
            zone = "Moderate"
        else:
            zone = "High"
        if zone not in zones:
            zones[zone] = 0
        zones[zone] += entry["duration"]
    return zones

def plot_progress(aggregated_data, metric):
    dates = [entry["date"] for entry in aggregated_data]
    values = [entry[metric] for entry in aggregated_data]
    plt.plot(dates, values)
    plt.xlabel("Date")
    plt.ylabel(metric)
    plt.title(f"Progress over Time ({metric})")
    return plt

def main():
    st.title("Physical Exercise Tag App")
    strava_athlete_id = st.text_input("Strava Athlete ID")
    strava_access_token = st.text_input("Strava Access Token")
    polar_user_id = st.text_input("Polar User ID")
    polar_access_token = st.text_input("Polar Access Token")
    myfitnesspal_user_id = st.text_input("MyFitnessPal User ID")
    myfitnesspal_password = st.text_input("MyFitnessPal Password", type="password")

    if st.button("Fetch Data"):
        strava_data = fetch_strava_data(strava_athlete_id, strava_access_token)
        polar_data = fetch_polar_data(polar_user_id, polar_access_token)
        myfitnesspal_data = fetch_myfitnesspal_data(myfitnesspal_user_id, myfitnesspal_password)
        aggregated_data = aggregate_data(strava_data, polar_data, myfitnesspal_data)
        heart_rate_zones = calculate_heart_rate_zones(aggregated_data)

        metric = st.selectbox("Select Metric", ["distance", "duration", "calories", "protein", "fat", "carbohydrates"])
        plot = plot_progress(aggregated_data, metric)
        st.pyplot(plot)

        st.write("Heart Rate Zones:")
        for zone, duration in heart_rate_zones.items():
            st.write(f"{zone}: {duration} minutes")

if __name__ == "__main__":
    main()
